sec = "IV.1"

w_yaml("left-r-module","left-r-module","Left R-Module","左R-模","definition","module-theory","basic",sec,"Definition 1.1")
w_tex("left-r-module",'Let $R$ be a ring. A (left) $R$-module is an additive abelian group $A$ together with a function $R \\times A \\to A$ (the image of $(r,a)$ being denoted by $ra$) such that for all $r,s \\in R$ and $a,b \\in A$:\n\\begin{enumerate}\n\\item[(i)] $r(a + b) = ra + rb$.\n\\item[(ii)] $(r + s)a = ra + sa$.\n\\item[(iii)] $r(sa) = (rs)a$.\n\\end{enumerate}\nIf $R$ has an identity element $1_R$ and\n\\begin{enumerate}\n\\item[(iv)] $1_R a = a$ for all $a \\in A$,\n\\end{enumerate}\nthen $A$ is said to be a \\emph{unitary} $R$-module. If $R$ is a division ring, then a unitary $R$-module is called a (left) \\emph{vector space}.\n')
w_intro("left-r-module","An $R$-module generalizes the notion of an abelian group (which is a $\\mathbb{Z}$-module) by allowing the scalars to come from an arbitrary ring $R$. The definition requires the additive abelian group structure plus a scalar multiplication satisfying distributivity and associativity axioms.\n"); cnt+=1

w_yaml("r-module-homomorphism","r-module-homomorphism","R-Module Homomorphism","R-模同态","definition","module-theory","basic",sec,"Definition 1.2")
w_tex("r-module-homomorphism",'Let $A$ and $B$ be modules over a ring $R$. A function $f : A \\to B$ is an \\emph{$R$-module homomorphism} provided that for all $a, c \\in A$ and $r \\in R$:\n\\[\nf(a + c) = f(a) + f(c) \\quad \\text{and} \\quad f(ra) = rf(a).\n\\]\nIf $R$ is a division ring, then an $R$-module homomorphism is called a \\emph{linear transformation}.\n')
w_intro("r-module-homomorphism","An $R$-module homomorphism is a structure-preserving map between $R$-modules: it respects both the additive group structure and the scalar multiplication. The kernel and image of a module homomorphism are submodules.\n"); cnt+=1

w_yaml("submodule","submodule","Submodule","子模","definition","module-theory","basic",sec,"Definition 1.3")
w_tex("submodule",'Let $R$ be a ring, $A$ an $R$-module and $B$ a nonempty subset of $A$. $B$ is a \\emph{submodule} of $A$ provided that $B$ is an additive subgroup of $A$ and $rb \\in B$ for all $r \\in R$, $b \\in B$. A submodule of a vector space over a division ring is called a \\emph{subspace}.\n')
w_intro("submodule","A submodule is a subset of a module that is itself a module under the same operations. The kernel and image of any module homomorphism are submodules, and intersections of submodules are again submodules.\n"); cnt+=1

w_yaml("submodule-generated-by-subset","submodule-generated-by-subset","Submodule Generated by a Subset","子集生成的子模","definition","module-theory","basic",sec,"Definition 1.4")
w_tex("submodule-generated-by-subset",'If $X$ is a subset of a module $A$ over a ring $R$, then the intersection of all submodules of $A$ containing $X$ is called the \\emph{submodule generated by $X$} (or \\emph{spanned by $X$}). If $X$ is finite and generates the module $B$, $B$ is said to be \\emph{finitely generated}. If $X = \\emptyset$, then the submodule generated by $X$ is the zero submodule.\n')
w_intro("submodule-generated-by-subset","The submodule generated by a subset $X$ is the smallest submodule containing $X$, obtained as the intersection of all submodules containing $X$. When $X$ is finite, the resulting module is called finitely generated.\n"); cnt+=1

w_yaml("quotient-module","quotient-module","Quotient Module","商模","theorem","module-theory","basic",sec,"Theorem 1.6")
w_tex("quotient-module",'Let $B$ be a submodule of a module $A$ over a ring $R$. Then the quotient group $A/B$ is an $R$-module with the action of $R$ on $A/B$ given by:\n\\[\nr(a + B) = ra + B \\quad \\text{for all } r \\in R, a \\in A.\n\\]\nThe map $\\pi : A \\to A/B$ given by $a \\mapsto a + B$ is an $R$-module epimorphism with kernel $B$.\n')
w_intro("quotient-module","The quotient module $A/B$ generalizes quotient groups to the module setting. The scalar multiplication is well-defined because $B$ is a submodule. The canonical projection $\\pi$ is a surjective module homomorphism with kernel exactly $B$.\n")
w_proof("quotient-module",sec,"direct-verification","Since $A$ is an additive abelian group, $B$ is a normal subgroup, and $A/B$ is a well-defined abelian group. If $a + B = a' + B$, then $a - a' \\in B$. Since $B$ is a submodule, $ra - ra' = r(a - a') \\in B$ for all $r \\in R$. Thus $ra + B = ra' + B$ by Corollary I.4.3 and the action of $R$ on $A/B$ is well defined. The remainder of the proof verifies the module axioms.\n"); cnt+=1

w_yaml("isomorphism-theorems-for-modules","isomorphism-theorems-for-modules","Isomorphism Theorems for Modules","模的同构定理","theorem","module-theory","basic",sec,"Theorem 1.7")
w_tex("isomorphism-theorems-for-modules","If $R$ is a ring and $f: A \\to B$ is an $R$-module homomorphism, then there is an $R$-module isomorphism\n\\[\nA/\\operatorname{Ker} f \\cong \\operatorname{Im} f.\n\\]")
w_intro("isomorphism-theorems-for-modules","The First Isomorphism Theorem for modules states that any module homomorphism induces an isomorphism between the quotient of the domain by the kernel and the image. All isomorphism theorems for groups carry over to modules, mutatis mutandis.\n"); cnt+=1

w_yaml("second-third-isomorphism-theorems-modules","second-third-isomorphism-theorems-modules","Second and Third Isomorphism Theorems for Modules","模的第二和第三同构定理","theorem","module-theory","basic",sec,"Theorem 1.9")
w_tex("second-third-isomorphism-theorems-modules",'Let $B$ and $C$ be submodules of a module $A$ over a ring $R$.\n\\begin{enumerate}\n\\item[(i)] There is an $R$-module isomorphism $B/(B \\cap C) \\cong (B + C)/C$;\n\\item[(ii)] if $C \\subset B$, then $B/C$ is a submodule of $A/C$, and there is an $R$-module isomorphism $(A/C)/(B/C) \\cong A/B$.\n\\end{enumerate}\n')
w_intro("second-third-isomorphism-theorems-modules","The Second Isomorphism Theorem relates the intersection and sum of submodules. The Third Isomorphism Theorem states that quotients of quotients simplify: $(A/C)/(B/C) \\cong A/B$ when $C \\subset B \\subset A$.\n")
w_proof("second-third-isomorphism-theorems-modules",sec,"group-theoretic-transfer","The proof follows from the corresponding group-theoretic isomorphism theorems (Corollaries I.5.9 and I.5.10), with the additional verification that all subgroup structures involved are actually submodules and that the isomorphisms respect the $R$-module structure.\n"); cnt+=1

w_yaml("correspondence-theorem-for-modules","correspondence-theorem-for-modules","Correspondence Theorem for Modules","模的对应定理","theorem","module-theory","basic",sec,"Theorem 1.10")
w_tex("correspondence-theorem-for-modules","If $R$ is a ring and $B$ is a submodule of an $R$-module $A$, then there is a one-to-one correspondence between the set of all submodules of $A$ containing $B$ and the set of all submodules of $A/B$, given by $C \\mapsto C/B$. Hence every submodule of $A/B$ is of the form $C/B$, where $C$ is a submodule of $A$ which contains $B$.\n")
w_intro("correspondence-theorem-for-modules","The Correspondence Theorem establishes a bijection between submodules of $A$ containing $B$ and submodules of the quotient $A/B$. This is the module-theoretic analogue of Theorem I.5.11.\n"); cnt+=1

w_yaml("direct-product-and-sum-of-modules","direct-product-and-sum-of-modules","Direct Product and Direct Sum of Modules","模的直积与直和","theorem","module-theory","basic",sec,"Theorem 1.11")
w_tex("direct-product-and-sum-of-modules",'Let $R$ be a ring and $\\{A_i \\mid i \\in I\\}$ a nonempty family of $R$-modules.\n\\begin{enumerate}\n\\item[(i)] $\\prod_{i \\in I} A_i$ is an $R$-module with $r\\{a_i\\} = \\{ra_i\\}$.\n\\item[(ii)] $\\sum_{i \\in I} A_i$ is a submodule of $\\prod_{i \\in I} A_i$.\n\\item[(iii)] For each $k \\in I$, the canonical projection $\\pi_k: \\prod A_i \\to A_k$ is an $R$-module epimorphism.\n\\item[(iv)] For each $k \\in I$, the canonical injection $\\iota_k: A_k \\to \\sum A_i$ is an $R$-module monomorphism.\n\\end{enumerate}\n')
w_intro("direct-product-and-sum-of-modules","Direct products and direct sums of modules are defined componentwise. The direct product is the Cartesian product with componentwise operations, while the direct sum is the submodule of elements with only finitely many nonzero components.\n"); cnt+=1

w_yaml("product-universal-property-modules","product-universal-property-modules","Universal Property of the Direct Product of Modules","模的直积的万有性质","theorem","module-theory","basic",sec,"Theorem 1.12")
w_tex("product-universal-property-modules",'If $R$ is a ring, $\\{A_i \\mid i \\in I\\}$ a family of $R$-modules, $C$ an $R$-module, and $\\{\\varphi_i : C \\to A_i \\mid i \\in I\\}$ a family of $R$-module homomorphisms, then there is a unique $R$-module homomorphism $\\varphi : C \\to \\prod_{i \\in I} A_i$ such that $\\pi_i \\varphi = \\varphi_i$ for all $i \\in I$. The direct product is uniquely determined up to isomorphism by this property.\n')
w_intro("product-universal-property-modules","The direct product satisfies the universal property of a categorical product in the category of $R$-modules: given a family of homomorphisms from a module $C$ to each $A_i$, there is a unique homomorphism from $C$ to the product making all diagrams commute.\n"); cnt+=1

w_yaml("coproduct-universal-property-modules","coproduct-universal-property-modules","Universal Property of the Direct Sum of Modules","模的直和的万有性质","theorem","module-theory","basic",sec,"Theorem 1.13")
w_tex("coproduct-universal-property-modules",'If $R$ is a ring, $\\{A_i \\mid i \\in I\\}$ a family of $R$-modules, $D$ an $R$-module, and $\\{\\psi_i : A_i \\to D \\mid i \\in I\\}$ a family of $R$-module homomorphisms, then there is a unique $R$-module homomorphism $\\psi : \\sum A_i \\to D$ such that $\\psi \\iota_i = \\psi_i$ for all $i \\in I$. The direct sum is uniquely determined up to isomorphism by this property.\n')
w_intro("coproduct-universal-property-modules","The direct sum satisfies the universal property of a categorical coproduct in the category of $R$-modules. The map is given by $\\psi(\\{a_i\\}) = \\sum_i \\psi_i(a_i)$, where the sum is over the finite set of indices with $a_i \\neq 0$.\n")
w_proof("coproduct-universal-property-modules",sec,"universal-property","By Theorem I.8.5 there is a unique abelian group homomorphism $\\psi : \\sum A_i \\to D$ with the desired property, given by $\\psi(\\{a_i\\}) = \\sum_i \\psi_i(a_i)$. It is easy to see that $\\psi$ is an $R$-module map. Hence $\\sum A_i$ is a coproduct in the category of $R$-modules (Definition I.7.4), and therefore determined up to isomorphism by Theorem I.7.5.\n"); cnt+=1

w_yaml("internal-direct-sum-characterization","internal-direct-sum-characterization","Internal Direct Sum Characterization","内直和的特征","theorem","module-theory","basic",sec,"Theorem 1.15")
w_tex("internal-direct-sum-characterization",'Let $R$ be a ring and $\\{A_i \\mid i \\in I\\}$ a family of submodules of an $R$-module $A$ such that\n\\begin{enumerate}\n\\item[(i)] $A$ is the sum of the family $\\{A_i \\mid i \\in I\\}$;\n\\item[(ii)] for each $k \\in I$, $A_k \\cap A_k^* = 0$, where $A_k^*$ is the sum of $\\{A_i \\mid i \\neq k\\}$.\n\\end{enumerate}\nThen there is an isomorphism $A \\cong \\sum_{i \\in I} A_i$.\n')
w_intro("internal-direct-sum-characterization","A module $A$ is the internal direct sum of submodules $\\{A_i\\}$ if it is generated by them and each submodule intersects the sum of the others trivially. Under these conditions, $A$ is isomorphic to the external direct sum of the $A_i$.\n"); cnt+=1

w_yaml("short-five-lemma","short-five-lemma","Short Five Lemma","短五引理","theorem","module-theory","intermediate",sec,"Theorem 1.17")
w_tex("short-five-lemma",'Let $R$ be a ring and\n\\[\n\\begin{array}{ccccccccc}\n0 & \\to & A & \\xrightarrow{f} & B & \\xrightarrow{g} & C & \\to & 0 \\\\\n& & \\alpha \\downarrow & & \\beta \\downarrow & & \\gamma \\downarrow & & \\\\\n0 & \\to & A\' & \\xrightarrow{f\'} & B\' & \\xrightarrow{g\'} & C\' & \\to & 0\n\\end{array}\n\\]\na commutative diagram of $R$-modules with exact rows. Then:\n\\begin{enumerate}\n\\item[(i)] If $\\alpha$ and $\\gamma$ are monomorphisms, then $\\beta$ is a monomorphism.\n\\item[(ii)] If $\\alpha$ and $\\gamma$ are epimorphisms, then $\\beta$ is an epimorphism.\n\\item[(iii)] If $\\alpha$ and $\\gamma$ are isomorphisms, then $\\beta$ is an isomorphism.\n\\end{enumerate}\n')
w_intro("short-five-lemma","The Short Five Lemma is a fundamental diagram-chasing result for short exact sequences. If two rows are short exact sequences and the outer vertical maps share a property (mono, epi, or iso), then the middle vertical map shares that property.\n")
w_proof("short-five-lemma",sec,"diagram-chase","(i) Suppose $\\alpha$ and $\\gamma$ are monomorphisms. To show $\\beta$ is a monomorphism, assume $\\beta(b) = 0$ for $b \\in B$. Then $\\gamma g(b) = g'\\beta(b) = 0$. Since $\\gamma$ is mono, $g(b) = 0$, so $b \\in \\operatorname{Ker} g = \\operatorname{Im} f$. Write $b = f(a)$ for $a \\in A$. Then $f'\\alpha(a) = \\beta f(a) = \\beta(b) = 0$. Since $f'$ is mono and $\\alpha$ is mono, $a = 0$, so $b = f(0) = 0$. Hence $\\beta$ is mono.\n\n(ii) Suppose $\\alpha$ and $\\gamma$ are epimorphisms. Let $b' \\in B'$. Then $g'(b') \\in C'$. Since $\\gamma$ is epi, $g'(b') = \\gamma(c)$ for some $c \\in C$. Since $g$ is epi, $c = g(b)$ for some $b \\in B$. Then $g'\\beta(b) = \\gamma g(b) = \\gamma(c) = g'(b')$, so $g'(\\beta(b) - b') = 0$. Thus $\\beta(b) - b' \\in \\operatorname{Ker} g' = \\operatorname{Im} f'$, say $\\beta(b) - b' = f'(a')$ for $a' \\in A'$. Since $\\alpha$ is epi, $a' = \\alpha(a)$ for some $a \\in A$. Consider $b - f(a) \\in B$: $\\beta(b - f(a)) = \\beta(b) - \\beta f(a) = \\beta(b) - f'\\alpha(a) = \\beta(b) - f'(a') = b'$. Hence $\\beta$ is epi.\n\n(iii) is an immediate consequence of (i) and (ii).\n"); cnt+=1

w_yaml("split-exact-sequence-characterization","split-exact-sequence-characterization","Split Exact Sequence Characterization","分裂正合列的特征","theorem","module-theory","intermediate",sec,"Theorem 1.18")
w_tex("split-exact-sequence-characterization",'Let $R$ be a ring and $0 \\to A \\xrightarrow{f} B \\xrightarrow{g} C \\to 0$ a short exact sequence of $R$-modules. Then the following conditions are equivalent:\n\\begin{enumerate}\n\\item[(i)] There is an $R$-module homomorphism $h : C \\to B$ such that $gh = 1_C$;\n\\item[(ii)] There is an $R$-module homomorphism $k : B \\to A$ such that $kf = 1_A$;\n\\item[(iii)] The given sequence is isomorphic to the direct sum short exact sequence $0 \\to A \\to A \\oplus C \\to C \\to 0$, and in particular $B \\cong A \\oplus C$.\n\\end{enumerate}\n')
w_intro("split-exact-sequence-characterization","A short exact sequence splits if it satisfies any of the three equivalent conditions: a right inverse (section) for the epimorphism, a left inverse (retraction) for the monomorphism, or isomorphism to the trivial direct sum sequence. Theorem 1.18 shows these are equivalent and that $B \\cong A \\oplus C$.\n")
w_proof("split-exact-sequence-characterization",sec,"diagram-chase","(i) $\\Rightarrow$ (ii) Given $h : C \\to B$ with $gh = 1_C$, for $b \\in B$, note that $b - hg(b) \\in \\operatorname{Ker} g = \\operatorname{Im} f$ since $g(b - hg(b)) = g(b) - ghg(b) = g(b) - g(b) = 0$. Define $k(b)$ as the unique $a \\in A$ with $f(a) = b - hg(b)$; verify $k$ is a homomorphism and $kf = 1_A$.\n\n(ii) $\\Rightarrow$ (iii) Define $\\varphi : B \\to A \\oplus C$ by $\\varphi(b) = (k(b), g(b))$ and $\\psi : A \\oplus C \\to B$ by $\\psi(a,c) = f(a) + h(c)$. By the Short Five Lemma, $\\varphi$ and $\\psi$ are isomorphisms.\n\n(iii) $\\Rightarrow$ (i), (ii) The canonical injection and projection of the direct sum pull back to give the required maps.\n"); cnt+=1

print(f"Section 1 done. Concepts so far: {cnt}")

