# SECTION 2: FREE MODULES AND VECTOR SPACES
# ============================================================
sec = "IV.2"

w_yaml("linear-independence-and-basis","linear-independence-and-basis","Linear Independence and Basis of a Module","模的线性无关与基","definition","module-theory","basic",sec,"Definition (unnumbered)")
w_tex("linear-independence-and-basis",'A subset $X$ of an $R$-module $A$ is said to be \\emph{linearly independent} provided that for distinct $x_1, \\ldots, x_n \\in X$ and $r_i \\in R$,\n\\[\nr_1x_1 + r_2x_2 + \\cdots + r_nx_n = 0 \\Rightarrow r_i = 0 \\text{ for every } i.\n\\]\nA set that is not linearly independent is \\emph{linearly dependent}. If $A$ is generated by a set $Y$, we say $Y$ \\emph{spans} $A$. A linearly independent subset of $A$ that spans $A$ is called a \\emph{basis}. The empty set is a basis of the zero module.\n')
w_intro("linear-independence-and-basis","These definitions generalize vector space notions to modules over an arbitrary ring. A basis is a linearly independent spanning set. Unlike vector spaces, not every module over an arbitrary ring possesses a basis; modules that do are called free modules.\n"); cnt+=1

w_yaml("free-module-characterization","free-module-characterization","Characterization of Free Modules","自由模的特征","theorem","module-theory","basic",sec,"Theorem 2.1")
w_tex("free-module-characterization",'Let $R$ be a ring with identity. The following conditions on a unitary $R$-module $F$ are equivalent:\n\\begin{enumerate}\n\\item[(i)] $F$ has a nonempty basis;\n\\item[(ii)] $F$ is the internal direct sum of a family of cyclic $R$-modules, each isomorphic to $R$;\n\\item[(iii)] $F$ is $R$-module isomorphic to a direct sum of copies of $R$;\n\\item[(iv)] there exists a nonempty set $X$ and a function $\\iota: X \\to F$ with the property: given any unitary $R$-module $A$ and function $f: X \\to A$, there exists a unique $R$-module homomorphism $\\bar{f}: F \\to A$ such that $\\bar{f}\\iota = f$.\n\\end{enumerate}\n')
w_intro("free-module-characterization","Theorem 2.1 gives four equivalent characterizations of a free module: having a basis, being an internal direct sum of copies of $R$, being isomorphic to an external direct sum of copies of $R$, and satisfying the universal property of a free object.\n")
w_proof("free-module-characterization",sec,"cyclical-equivalence","(i) $\\Rightarrow$ (ii) Let $X$ be a basis. For each $x \\in X$, $Rx \\cong R$. Since $X$ is linearly independent and spans $F$, $F = \\sum_{x \\in X} Rx$ is an internal direct sum. (ii) $\\Rightarrow$ (iii) By definition of internal direct sum. (iii) $\\Rightarrow$ (i) The elements $\\theta_x$ with $1_R$ in coordinate $x$ and $0$ elsewhere form a basis. (i) $\\Rightarrow$ (iv) Given $f: X \\to A$, define $\\bar{f}(\\sum r_i x_i) = \\sum r_i f(x_i)$. Linear independence ensures well-definedness. Uniqueness follows since $X$ generates $F$. (iv) $\\Rightarrow$ (iii) Construct $\\sum_{x \\in X} R$ and use the free object property.\n"); cnt+=1

w_yaml("homomorphic-image-of-free-module","homomorphic-image-of-free-module","Every Module is a Homomorphic Image of a Free Module","每个模都是自由模的同态像","corollary","module-theory","basic",sec,"Corollary 2.2")
w_tex("homomorphic-image-of-free-module","Every unitary module $A$ over a ring $R$ with identity is the homomorphic image of a free $R$-module.\n")
w_intro("homomorphic-image-of-free-module","Corollary 2.2 states that every module can be expressed as a quotient of a free module. This shows that free modules play the role of universal preimages in module theory.\n")
w_proof("homomorphic-image-of-free-module",sec,"universal-property","Let $X$ be a set of generators of $A$ and $F$ the free $R$-module on $X$. The inclusion map $X \\to A$ induces an $R$-module homomorphism $\\bar{f}: F \\to A$ such that $X \\subset \\operatorname{Im} \\bar{f}$ (Theorem 2.1(iv)). Since $X$ generates $A$, $\\operatorname{Im} \\bar{f} = A$.\n"); cnt+=1

w_yaml("maximal-linearly-independent-subset-is-basis","maximal-linearly-independent-subset-is-basis","Maximal Linearly Independent Subset is a Basis","极大线性无关子集是基","lemma","module-theory","basic",sec,"Lemma 2.3")
w_tex("maximal-linearly-independent-subset-is-basis","A maximal linearly independent subset $X$ of a vector space $V$ over a division ring $D$ is a basis of $V$.\n")
w_intro("maximal-linearly-independent-subset-is-basis","In a vector space, any linearly independent subset that is maximal with respect to inclusion is necessarily a basis. The proof shows that if such a maximal set did not span, one could add a vector not in its span to get a larger linearly independent set, contradicting maximality.\n")
w_proof("maximal-linearly-independent-subset-is-basis",sec,"maximality-argument","Let $W$ be the subspace spanned by $X$. Since $X$ is linearly independent and spans $W$, $X$ is a basis of $W$. If $W = V$, we are done. If not, there exists $a \\in V$, $a \\notin W$. Consider $X \\cup \\{a\\}$. If $ra + \\sum r_i x_i = 0$ with $r \\neq 0$, then $a = -r^{-1}\\sum r_i x_i \\in W$, contradiction. Hence $r = 0$ and all $r_i = 0$, so $X \\cup \\{a\\}$ is linearly independent, contradicting maximality. Therefore $W = V$.\n"); cnt+=1

w_yaml("every-vector-space-has-basis","every-vector-space-has-basis","Every Vector Space Has a Basis","每个向量空间都有基","theorem","module-theory","basic",sec,"Theorem 2.4")
w_tex("every-vector-space-has-basis","Every vector space $V$ over a division ring $D$ has a basis. Consequently, every vector space is a free $D$-module.\n")
w_intro("every-vector-space-has-basis","Theorem 2.4 is fundamental: every vector space possesses a basis. The proof uses Zorn's Lemma to find a maximal linearly independent subset of any spanning set, then invokes Lemma 2.3 to conclude it is a basis.\n")
w_proof("every-vector-space-has-basis",sec,"zorns-lemma","Let $X$ be any subset that spans $V$ (e.g., $V$ itself). Partially order the set $S$ of all linearly independent subsets of $X$ by inclusion. Zorn's Lemma implies the existence of a maximal linearly independent subset $Y$ of $X$. Every element of $X$ is a linear combination of elements of $Y$ (otherwise we could construct a larger linearly independent subset). Since $X$ spans $V$, so does $Y$. Hence $Y$ is a basis.\n"); cnt+=1

w_yaml("infinite-basis-cardinality-invariance","infinite-basis-cardinality-invariance","Invariance of Cardinality for Infinite Bases","无限基的基数不变性","theorem","module-theory","intermediate",sec,"Theorem 2.6")
w_tex("infinite-basis-cardinality-invariance","Let $R$ be a ring with identity and $F$ a free $R$-module with an infinite basis $X$. Then every basis of $F$ has the same cardinality as $X$.\n")
w_intro("infinite-basis-cardinality-invariance","For free modules over an arbitrary ring with identity, the cardinality of an infinite basis is invariant. The proof uses the fact that each element of another basis $Y$ is a finite linear combination of elements of $X$.\n")
w_proof("infinite-basis-cardinality-invariance",sec,"cardinality-comparison","If $Y$ is another basis, $Y$ must be infinite (otherwise a finite subset of $X$ would generate $F$). Let $K(Y)$ be the set of all finite subsets of $Y$. Define $f: X \\to K(Y)$ by mapping $x$ to the finite set of basis elements from $Y$ appearing in its expression. Each finite subset of $Y$ has at most finitely many preimages, so $|X| \\le |K(Y)| \\cdot \\aleph_0 = |Y|$ (since $Y$ is infinite). Interchanging $X$ and $Y$ gives $|Y| \\le |X|$. By Schroeder-Bernstein, $|X| = |Y|$.\n"); cnt+=1

w_yaml("vector-space-basis-cardinality-invariance","vector-space-basis-cardinality-invariance","Any Two Bases of a Vector Space Have the Same Cardinality","向量空间任意两组基有相同的基数","theorem","module-theory","basic",sec,"Theorem 2.7")
w_tex("vector-space-basis-cardinality-invariance","If $V$ is a vector space over a division ring $D$, then any two bases of $V$ have the same cardinality.\n")
w_intro("vector-space-basis-cardinality-invariance","Theorem 2.7 establishes that dimension is well-defined for vector spaces. The infinite case follows from Theorem 2.6; the finite case uses a replacement argument.\n")
w_proof("vector-space-basis-cardinality-invariance",sec,"replacement-argument","If either basis is infinite, Theorem 2.6 applies. For finite bases $X = \\{x_1,\\ldots,x_n\\}$ and $Y = \\{y_1,\\ldots,y_m\\}$, suppose $m$ minimal. Express $y_m$ in terms of $X$; a nonzero coefficient identifies an $x_k$ that can be replaced by $y_m$ while preserving spanning. Repeating this process replaces all $x_i$ with $y_j$, showing $m = n$ by minimality.\n"); cnt+=1

w_yaml("rank-and-invariant-dimension-property","rank-and-invariant-dimension-property","Rank of a Free Module and the Invariant Dimension Property","自由模的秩与不变维数性质","definition","module-theory","basic",sec,"Definition 2.8")
w_tex("rank-and-invariant-dimension-property",'A ring $R$ with identity has the \\emph{invariant dimension property} (or IBN) if for every free $R$-module $F$, any two bases have the same cardinality. The cardinal number $|X|$ of any basis $X$ of $F$ is called the \\emph{rank} (or \\emph{dimension}) of $F$, denoted $\\operatorname{rank} F$.\n')
w_intro("rank-and-invariant-dimension-property","A ring has IBN if the rank of every free module is well-defined. Not all rings have IBN (Exercise 13). Commutative rings (Corollary 2.12) and division rings (Theorem 2.7) do have it.\n"); cnt+=1

w_yaml("quotient-of-free-module-by-ideal","quotient-of-free-module-by-ideal","Quotient of a Free Module by an Ideal","自由模关于理想的商","theorem","module-theory","basic",sec,"Theorem 2.10")
w_tex("quotient-of-free-module-by-ideal",'Let $R$ be a ring with identity, $I$ a proper ideal of $R$, and $F$ a free $R$-module with basis $X$. Then $F/IF$ is a free $R/I$-module with basis $\\pi(X) = \\{x + IF \\mid x \\in X\\}$ of cardinality $|X|$.\n')
w_intro("quotient-of-free-module-by-ideal","Theorem 2.10 describes how a free module behaves under reduction modulo an ideal: $F/IF$ becomes a free module over $R/I$, and the image of a basis forms a basis of the quotient.\n")
w_proof("quotient-of-free-module-by-ideal",sec,"basis-verification","If $u + IF \\in F/IF$, write $u = \\sum r_j x_j$. Then $u + IF = \\sum (r_j + I)(x_j + IF)$, so $\\pi(X)$ generates $F/IF$. For linear independence: if $\\sum (r_k + I)\\pi(x_k) = 0$, then $\\sum r_k x_k \\in IF$, so $\\sum r_k x_k = \\sum s_j u_j$ with $s_j \\in I$. Expanding gives coefficients in $I$, so by linear independence over $R$, each $r_k \\in I$. Hence $r_k + I = 0$ in $R/I$, and $\\pi(X)$ is linearly independent.\n"); cnt+=1

w_yaml("commutative-rings-invariant-dimension","commutative-rings-invariant-dimension","Commutative Rings Have the Invariant Dimension Property","交换环具有不变维数性质","corollary","module-theory","intermediate",sec,"Corollary 2.12")
w_tex("commutative-rings-invariant-dimension","Every commutative ring $R$ with identity has the invariant dimension property.\n")
w_intro("commutative-rings-invariant-dimension","Corollary 2.12 is crucial: over a commutative ring with identity, the rank of a free module is well-defined. The proof reduces to the vector space case via a maximal ideal.\n")
w_proof("commutative-rings-invariant-dimension",sec,"reduction-to-field","Let $I$ be a maximal ideal of $R$. Then $R/I$ is a field. If $X$ and $Y$ are bases of $F$, then $\\pi(X)$ and $\\pi(Y)$ are bases of the vector space $F/IF$ over $R/I$ by Theorem 2.10. By Theorem 2.7, $|\\pi(X)| = |\\pi(Y)|$. Since $\\pi$ is injective on bases, $|X| = |Y|$.\n"); cnt+=1

w_yaml("subspace-dimension-properties","subspace-dimension-properties","Dimension Properties of Subspaces","子空间的维数性质","theorem","module-theory","basic",sec,"Theorem 2.13")
w_tex("subspace-dimension-properties",'Let $W$ be a subspace of a vector space $V$ over a division ring $D$.\n\\begin{enumerate}\n\\item[(i)] $\\dim_D W \\leq \\dim_D V$;\n\\item[(ii)] if $\\dim_D W = \\dim_D V$ and $\\dim_D V$ is finite, then $W = V$;\n\\item[(iii)] $\\dim_D V = \\dim_D W + \\dim_D(V/W)$.\n\\end{enumerate}\n')
w_intro("subspace-dimension-properties","Theorem 2.13 collects essential dimension formulas: the dimension of a subspace never exceeds that of the ambient space; equality of finite dimensions forces equality of spaces; dimension is additive over quotients.\n")
w_proof("subspace-dimension-properties",sec,"basis-extension","(i) Let $Y$ be a basis of $W$. By Theorem 2.4 there is a basis $X$ of $V$ containing $Y$, so $\\dim W = |Y| \\le |X| = \\dim V$.\n(ii) If $|Y| = |X|$ and $|X|$ is finite, $Y = X$, so $W = V$.\n(iii) Show $U = \\{x + W \\mid x \\in X - Y\\}$ is a basis of $V/W$. $U$ spans because any $v = \\sum r_i y_i + \\sum s_j x_j$ gives $v + W = \\sum s_j(x_j + W)$. Linear independence follows from linear independence of $X$. Thus $\\dim V = |X| = |Y| + |X-Y| = \\dim W + \\dim(V/W)$.\n"); cnt+=1

w_yaml("dimension-formula-tower-of-division-rings","dimension-formula-tower-of-division-rings","Dimension Formula for a Tower of Division Rings","除环塔的维数公式","theorem","module-theory","intermediate",sec,"Theorem 2.16")
w_tex("dimension-formula-tower-of-division-rings",'Let $R,S,T$ be division rings such that $R \\subset S \\subset T$. Then\n\\[\n\\dim_R T = (\\dim_S T)(\\dim_R S).\n\\]\nFurthermore, $\\dim_R T$ is finite if and only if $\\dim_S T$ and $\\dim_R S$ are finite.\n')
w_intro("dimension-formula-tower-of-division-rings","This is the multiplicative formula for dimensions in a tower of division rings, generalizing the degree formula for field extensions. A basis of $T$ over $R$ is obtained by multiplying bases of $T$ over $S$ and $S$ over $R$.\n")
w_proof("dimension-formula-tower-of-division-rings",sec,"basis-multiplication","Let $U$ be a basis of $T$ over $S$ and $V$ a basis of $S$ over $R$. Show $\\{vu \\mid v \\in V, u \\in U\\}$ is a basis of $T$ over $R$. Spanning: any $t = \\sum s_i u_i$ with $s_i \\in S$, each $s_i = \\sum r_{ij} v_j$, so $t = \\sum \\sum r_{ij} v_j u_i$. Linear independence: if $\\sum \\sum r_{ij}(v_j u_i) = 0$, let $s_i = \\sum r_{ij} v_j$. Then $\\sum s_i u_i = 0$, so each $s_i = 0$ (independence of $U$), then each $r_{ij} = 0$ (independence of $V$). Thus $\\dim_R T = |U||V| = (\\dim_S T)(\\dim_R S)$.\n"); cnt+=1

